#!/usr/bin/env node
/**
 * xterm.js / xterm-addon-fit / xterm.css を node_modules から読み込んで
 * src/assets/xtermBundle.generated.ts にインライン文字列として書き出す。
 *
 * iOS WKWebView は外部 CDN スクリプト (<script src="https://...">) を
 * ブロッキングロードするため、ネットワーク障害時にページ全体がハングする。
 * インライン埋め込みにすることでこの問題を回避する。
 */

const fs = require('fs')
const path = require('path')

const nmDir = path.resolve(__dirname, '../node_modules')
const outPath = path.resolve(__dirname, '../src/assets/xtermBundle.generated.ts')

function readAndEscape(filePath) {
  const content = fs.readFileSync(filePath, 'utf8')
  // テンプレートリテラル内のバッククォートとバックスラッシュをエスケープ
  return content.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${')
}

const xtermJs = readAndEscape(path.join(nmDir, 'xterm/lib/xterm.js'))
const xtermCss = readAndEscape(path.join(nmDir, 'xterm/css/xterm.css'))
const xtermFitJs = readAndEscape(path.join(nmDir, 'xterm-addon-fit/lib/xterm-addon-fit.js'))

const output = `// AUTO-GENERATED by scripts/build-xterm-bundle.js — do not edit manually
// Run: node scripts/build-xterm-bundle.js

export const xtermJs = \`${xtermJs}\`

export const xtermCss = \`${xtermCss}\`

export const xtermFitJs = \`${xtermFitJs}\`
`

fs.writeFileSync(outPath, output, 'utf8')
console.log(`✓ xtermBundle.generated.ts written (${Math.round(output.length / 1024)} KB)`)
